#include<bits/stdc++.h>
using namespace std;
int n;
double z=0;
struct node {
	int x, y,z;
} a[50005];
bool cmp(node a, node b) {
	return a.z < b.z;
}
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) cin >> a[i].x >> a[i].y>>a[i].z;
	sort(a + 1, a + n + 1, cmp);
	for (int i = 2; i <= n; i++) {
		z+=sqrt((a[i-1].x-a[i].x)*1.0*(a[i-1].x-a[i].x)+(a[i-1].y-a[i].y)*(a[i-1].y-a[i].y)+(a[i-1].z-a[i].z)*(a[i-1].z-a[i].z));
	}
	printf("%.3lf",z);
	return 0;
}
